#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // Write packet_id (POD type, will be written as-is)
        stream & packet_id;

        // Write username with length prefix using prefixed adaptor
        stream & hexi::prefixed(username);

        // Write scores with length prefix followed by elements using prefixed adaptor
        stream & hexi::prefixed(scores);

        // Write metadata as null-terminated string using null_terminated adaptor
        stream & hexi::null_terminated(metadata);
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    // Create a buffer to hold the serialized data
    std::vector<uint8_t> buffer;

    // Create a binary_stream that writes to the buffer
    hexi::binary_stream<std::vector<uint8_t>> stream(buffer);

    // Use the stream's serialise method to serialize the packet
    stream.serialise(packet);

    // Return the buffer containing the serialized data
    return buffer;
}
```

## Explanation:

1. **Serialization Order**: The `serialise` method follows the exact order specified:
   - `packet_id` (POD type, written as-is)
   - `username` with length prefix using `hexi::prefixed`
   - `scores` with length prefix followed by elements using `hexi::prefixed`
   - `metadata` as null-terminated string using `hexi::null_terminated`

2. **Adaptor Usage**: 
   - `hexi::prefixed` adds a length prefix before the actual data
   - `hexi::null_terminated` writes the string followed by a null terminator

3. **Stream Operations**: The `&` operator is used to serialize each member, which internally calls `operator<<` as shown in the reference materials.

4. **Buffer Handling**: The `std::vector<uint8_t>` buffer is properly used with `hexi::binary_stream` to capture the serialized data.

