    hexi::buffer_adaptor adaptor(buffer);

    // Check if the requested bytes_to_peek is within the available data
    if (adaptor.size() < bytes_to_peek) {
        // Throw an exception if there's not enough data
        HEXI_THROW(hexi::buffer_underrun(adaptor.size(), bytes_to_peek, 0));
    }

    // Create a destination vector to hold the peeked data
    std::vector<uint8_t> destination(bytes_to_peek);

    // Use the copy() method to copy data without advancing the read pointer
    adaptor.copy(destination.data(), bytes_to_peek);

    // Return the copied data
    return destination;
}

