#include <cstdint>

void write_container_to_stream(hexi::pmc::binary_stream_writer& writer, const std::vector<uint32_t>& container) {
    // Write the container with prefixed count using the provided operator<<
    writer << hexi::pmc::prefixed(container);
}

std::vector<uint32_t> read_container_from_stream(hexi::pmc::binary_stream_reader& reader) {
    std::vector<uint32_t> container;

    // Read the count using the provided operator>> for uint32_t with little endian conversion
    uint32_t count = 0;
    reader >> hexi::pmc::endian::le(count);

    // Read the elements using the provided operator>> for the container
    for (uint32_t i = 0; i < count; ++i) {
        uint32_t element;
        reader >> element;
        container.push_back(element);
    }

    return container;
}

