#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>

std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // Create a buffer (vector) and ensure it has enough space
    std::vector<uint8_t> buffer;
    buffer.resize(input_data.size()); // Pre-size the buffer

    // Create buffer_write_adaptor
    hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>> writer(buffer);

    // Check available space and write data
    if (writer.free() < input_data.size()) {
        // Resize buffer if needed (though we pre-sized, this handles edge cases)
        buffer.resize(input_data.size());
        writer = hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>>(buffer);
    }

    writer.write(input_data.data(), input_data.size());

    // Create buffer_read_adaptor and read data back
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>> reader(buffer);

    // Verify readable size matches what we wrote
    if (reader.size() != input_data.size()) {
        return {};
    }

    std::vector<uint8_t> output_data(input_data.size());
    reader.read(output_data.data(), output_data.size());

    return output_data;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data, std::size_t peek_size) {
    // Create buffer_read_adaptor
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>> adaptor(buffer_data);

    // Check if we have enough data to peek
    if (peek_size > adaptor.size()) {
        return {};
    }

    // Peek at data without advancing read pointer
    std::vector<uint8_t> peek_buffer(peek_size);
    adaptor.copy(peek_buffer.data(), peek_size);

    // Consume the data by reading it
    adaptor.read(peek_buffer.data(), peek_size);

    return peek_buffer;
}
